import React, { createContext, useContext, useState } from "react";

const KycContext = createContext();

export function useKyc() {
  return useContext(KycContext);
}

// simple incremental ids for demo
let nextRequestId = 1;

export function KycProvider({ children }) {
  const [requests, setRequests] = useState([]);
  // walletAddress -> { level, expiry, issuer, lastUpdated }
  const [issuedKyc, setIssuedKyc] = useState({});

  // -------- USER REQUEST FLOW --------
  const requestKyc = (payload) => {
    const now = new Date().toISOString();
    setRequests((prev) => [
      ...prev,
      {
        id: nextRequestId++,
        status: "pending",
        createdAt: now,
        updatedAt: now,
        ...payload
      }
    ]);
  };

  const updateRequestStatus = (id, status) => {
    setRequests((prev) =>
      prev.map((r) =>
        r.id === id ? { ...r, status, updatedAt: new Date().toISOString() } : r
      )
    );
  };

  const approveRequest = (id, { level, expiry, issuer }) => {
    let target;
    setRequests((prev) =>
      prev.map((r) => {
        if (r.id === id) target = r;
        return r.id === id
          ? { ...r, status: "approved", updatedAt: new Date().toISOString() }
          : r;
      })
    );
    if (target) {
      // also create / update issuedKyc for that wallet
      const wallet = target.walletAddress;
      setIssuedKyc((prev) => ({
        ...prev,
        [wallet]: {
          walletAddress: wallet,
          fullName: target.fullName,
          level,
          expiry,
          issuer,
          lastUpdated: new Date().toISOString()
        }
      }));
    }
  };

  const rejectRequest = (id) => updateRequestStatus(id, "rejected");

  // -------- MANUAL ISSUE / UPDATE FLOW (ISSUER) --------
  const issueOrUpdateKyc = ({ walletAddress, fullName, level, expiry, issuer }) => {
    setIssuedKyc((prev) => ({
      ...prev,
      [walletAddress]: {
        walletAddress,
        fullName,
        level,
        expiry,
        issuer,
        lastUpdated: new Date().toISOString()
      }
    }));
  };

  // -------- USER VIEW / UPDATE (METAMASK) --------
  const getKycForWallet = (walletAddress) => {
    if (!walletAddress) return null;
    return issuedKyc[walletAddress.toLowerCase()] || issuedKyc[walletAddress] || null;
  };

  const userUpdateKycRequest = ({ walletAddress }) => {
    const now = new Date().toISOString();
    setRequests((prev) => [
      ...prev,
      {
        id: nextRequestId++,
        status: "pending",
        createdAt: now,
        updatedAt: now,
        type: "update",
        walletAddress
      }
    ]);
  };

  return (
    <KycContext.Provider
      value={{
        requests,
        issuedKyc,
        requestKyc,
        approveRequest,
        rejectRequest,
        issueOrUpdateKyc,
        getKycForWallet,
        userUpdateKycRequest
      }}
    >
      {children}
    </KycContext.Provider>
  );
}
